<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#E06C75">    mongo-cache</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66">true</span></span>
